"use client";
import { useState } from "react"; // Put your illustration in public folder
import { UserPlus, CornerDownLeft, Mail, Lock, User, Key } from 'lucide-react';

export default function LoginPage() {
  const [fullName, setFullName] = useState("");
  const [email, setEmail] = useState("");
  const [universityId, setUniversityId] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = (e) => {
    e.preventDefault();
    setMessage(null);

    if (password !== confirmPassword) {
      setMessage({ type: "error", text: "Error: Passwords do not match." });
      return;
    }

    if (!fullName || !email || !password) {
      setMessage({
        type: "error",
        text: "Error: Please fill in all required fields.",
      });
      return;
    }
    setIsLoading(true);

    console.log("Registration attempt:", { fullName, email, universityId });

    setTimeout(() => {
      setIsLoading(false);
      setMessage({
        type: 'success',
        text: `Registration successful for ${fullName}! A verification link has been sent to ${email}.`,
      });
      // In a real app, you would submit this to Firebase Auth/Firestore here
    }, 1500);
  };

  return (
    <div className="min-h-screen px-20 flex">
      {/* Left Side */}
      <div className="w-1/2 bg-white flex flex-col justify-center items-start px-20">
       <div className="flex-row">
            <h1 className="text-2xl font-semibold mb-2">
            <UserPlus className="w-7 h-7 mr-2 text-teal-600" />
         Register as a new user
        </h1>
       </div>
        

        <form onSubmit={handleLogin} className="w-full flex flex-col space-y-4">
             <User className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400" />
          <input
            type="text"
            placeholder="Email address"
            className="border max-w-100 h-10 border-gray-300 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />

          <input
            type="password"
            placeholder="Password"
            className="border border-gray-300   max-w-100 h-10 rounded-lg p-3 focus:outline-none focus:ring-2 focus:ring-blue-400"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button
            type="submit"
            className="bg-blue-500  max-w-40 h-10 text-white  rounded-lg hover:bg-blue-600 transition"
          >
            Sign In
          </button>
        </form>

        <a href="#" className="text-blue-500 mt-3 text-sm hover:underline">
          Forgot password?
        </a>
      </div>

      {/* Right Side */}
      <div className="w-1/2 hover:scale-100 transition-transform duration-300  flex justify-center items-center">
        <img src="./login.jpg" alt="Login Hero" className="max-w-lg" />
      </div>
    </div>
  );
}
